[
    {
        "role": "paragraph",
        "segment": "The critical path is the longest path in a project schedule for which the slack at every node is zero.",
        "citations": [
            {
                "type": "source_text",
                "content": "The longest path has a slack of zero for each of its nodes, because it is the path that determines whether or not the project is on schedule. For this reason, it is called the critical path.",
                "img_id": null
            }
        ],
        "type": null
    },
    {
        "role": "paragraph",
        "segment": "It determines which activities must be completed on schedule to avoid delay, and it has no slack, meaning there is no margin for error when performing the activities along its route.",
        "citations": [
            {
                "type": "source_text",
                "content": "Since the critical path has no slack, there is no margin for error when performing the activities along its route.",
                "img_id": null
            },
            {
                "type": "source_text",
                "content": "Critical path analysis of a project schedule tells us who must wait for what as the project is being developed. It also tells us which activities must be completed on schedule to avoid delay.",
                "img_id": null
            }
        ],
        "type": null
    },
    {
        "role": "paragraph",
        "segment": "If an activity on the critical path begins late, it pushes all subsequent critical path activities forward, forcing them to be late as well if there is no slack.",
        "citations": [
            {
                "type": "source_text",
                "content": "Notice what happens when an activity on the critical path begins late (i.e., later than its earliest start time). The late start pushes all subsequent critical path activities forward, forcing them to be late, too, if there is no slack.",
                "img_id": null
            }
        ],
        "type": null
    }
]

